using Microsoft.EntityFrameworkCore;

namespace CosmosProject;

// Breaking change #3: EF Core 9 Cosmos provider renamed the discriminator
// property from "Discriminator" to "$type". For existing documents that
// already store "Discriminator", you must explicitly configure the old name.
//
// Breaking change #4: EF Core 9 Cosmos provider no longer supports synchronous
// I/O. All queries must use async (ToListAsync, FirstOrDefaultAsync, etc.).

class CosmosDbContext : DbContext
{
    public DbSet<Vehicle> Vehicles => Set<Vehicle>();

    protected override void OnConfiguring(DbContextOptionsBuilder options)
    {
        options.UseCosmos(
            "AccountEndpoint=https://localhost:8081/;AccountKey=C2y6yDjf5/R+ob0N8A7Cgv30VRDJIWEHLM+4QDU5DE2nQ9nDuVTqobD4b8mGGyPMbIZnqyMsEcaGQy67XIw/Jw==",
            "SampleDb");
    }

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Vehicle>(entity =>
        {
            entity.ToContainer("Vehicles");
            entity.HasPartitionKey(v => v.PartitionKey);
            entity.HasNoDiscriminator(); // Option A: if only one entity type per container

            // Option B (preferred for existing documents with "Discriminator" property):
            // entity.HasDiscriminator<string>("Discriminator");
        });

        // For a hierarchy stored in one container with existing "Discriminator" values:
        modelBuilder.Entity<Car>(entity =>
        {
            entity.ToContainer("AllVehicles");
            entity.HasPartitionKey(c => c.PartitionKey);

            // Explicitly set the discriminator property name to match existing documents
            entity.HasDiscriminator<string>("Discriminator")
                  .HasValue<Car>("Car")
                  .HasValue<Truck>("Truck");
        });
    }
}

class Vehicle
{
    public string Id { get; set; } = null!;
    public string PartitionKey { get; set; } = null!;
    public string Name { get; set; } = null!;
}

class Car : Vehicle
{
    public int Seats { get; set; }
}

class Truck : Vehicle
{
    public double PayloadTons { get; set; }
}

// Breaking change fix: sync → async
class VehicleService(CosmosDbContext db)
{
    // BEFORE (EF Core 8 allowed sync):
    //   var cars = db.Vehicles.Where(v => v.Name == "X").ToList();
    //
    // AFTER (EF Core 9 requires async for Cosmos):
    public async Task<List<Vehicle>> GetVehiclesAsync(string name)
    {
        return await db.Vehicles
            .Where(v => v.Name == name)
            .ToListAsync();
    }
}

